import { describe, expect, it } from 'vitest';

import {
  ReasoningChainValidator,
  coherenceRatio,
  type ChainVerdict,
  type ReasoningStep,
} from '../src/pleromatic-reasoning-validator';
import { Verdict, isDefer, isReject } from '@a0n/bitwise/triton-verdict';

describe('ReasoningChainValidator — vacuous and singleton chains', () => {
  it('empty chain is vacuously valid', () => {
    const v = new ReasoningChainValidator();
    const verdict = v.validateChain([]);
    expect(verdict.valid).toBe(true);
    if (verdict.valid) {
      expect(verdict.stepCount).toBe(0);
      expect(verdict.foldStepsTotal).toBe(0);
    }
  });

  it('singleton at grounding (10) is valid with 0 fold steps', () => {
    const v = new ReasoningChainValidator();
    const verdict = v.validateChain([{ closurePosition: 10 }]);
    expect(verdict.valid).toBe(true);
    if (verdict.valid) {
      expect(verdict.stepCount).toBe(1);
      expect(verdict.foldStepsTotal).toBe(0);
    }
  });
});

describe('ReasoningChainValidator — multi-step ascending chains', () => {
  it('valid 3-step ascent [10, 30, 90] sums fold steps to 0+1+2=3', () => {
    const v = new ReasoningChainValidator();
    const verdict = v.validateChain([
      { closurePosition: 10, label: 'ground' },
      { closurePosition: 30, label: 'depth-1' },
      { closurePosition: 90, label: 'depth-2' },
    ]);
    expect(verdict.valid).toBe(true);
    if (verdict.valid) {
      expect(verdict.stepCount).toBe(3);
      expect(verdict.foldStepsTotal).toBe(3);
    }
  });

  it('valid 4-step chain [10, 30, 90, 270] sums to 0+1+2+3=6', () => {
    const v = new ReasoningChainValidator();
    const verdict = v.validateChain([
      { closurePosition: 10 },
      { closurePosition: 30 },
      { closurePosition: 90 },
      { closurePosition: 270 },
    ]);
    expect(verdict.valid).toBe(true);
    if (verdict.valid) expect(verdict.foldStepsTotal).toBe(6);
  });
});

describe('ReasoningChainValidator — failure modes', () => {
  it('rejects a step not in the closure tower (e.g., 11)', () => {
    const v = new ReasoningChainValidator();
    const verdict = v.validateChain([
      { closurePosition: 30 },
      { closurePosition: 11, label: 'rogue' },
    ]);
    expect(verdict.valid).toBe(false);
    if (!verdict.valid) {
      expect(verdict.failedAtIndex).toBe(1);
      expect(verdict.reason).toBe('not-in-tower');
      expect(verdict.failedStep.closurePosition).toBe(11);
      expect(verdict.failedStep.label).toBe('rogue');
    }
  });

  it('rejects a step below grounding (e.g., 5)', () => {
    const v = new ReasoningChainValidator();
    const verdict = v.validateChain([{ closurePosition: 5 }]);
    expect(verdict.valid).toBe(false);
    if (!verdict.valid) {
      expect(verdict.failedAtIndex).toBe(0);
      expect(verdict.reason).toBe('below-grounding');
    }
  });

  it('rejects at the FIRST failing step, ignoring later steps', () => {
    const v = new ReasoningChainValidator();
    const verdict = v.validateChain([
      { closurePosition: 10 },
      { closurePosition: 31 }, // not-in-tower
      { closurePosition: 90 }, // would be valid, but never reached
    ]);
    expect(verdict.valid).toBe(false);
    if (!verdict.valid) {
      expect(verdict.failedAtIndex).toBe(1);
      expect(verdict.reason).toBe('not-in-tower');
    }
  });
});

describe('ReasoningChainValidator — streaming early exit', () => {
  it('streaming variant stops the generator on first failure', () => {
    const yielded: number[] = [];
    function* chain(): Generator<ReasoningStep> {
      yielded.push(0);
      yield { closurePosition: 30 };
      yielded.push(1);
      yield { closurePosition: 11 }; // fails — not in tower
      yielded.push(2);
      yield { closurePosition: 90 };
    }

    const v = new ReasoningChainValidator();
    const verdict: ChainVerdict = v.validateChainStreaming(chain());
    expect(verdict.valid).toBe(false);
    if (!verdict.valid) {
      expect(verdict.failedAtIndex).toBe(1);
      expect(verdict.reason).toBe('not-in-tower');
    }
    // Generator should have yielded the failing step but NOT advanced
    // past it — `yielded` must contain 0 and 1 but NOT 2.
    expect(yielded).toContain(0);
    expect(yielded).toContain(1);
    expect(yielded).not.toContain(2);
  });

  it('streaming variant validates a full valid chain', () => {
    function* chain(): Generator<ReasoningStep> {
      yield { closurePosition: 10 };
      yield { closurePosition: 30 };
      yield { closurePosition: 90 };
    }
    const v = new ReasoningChainValidator();
    const verdict = v.validateChainStreaming(chain());
    expect(verdict.valid).toBe(true);
    if (verdict.valid) {
      expect(verdict.stepCount).toBe(3);
      expect(verdict.foldStepsTotal).toBe(3);
    }
  });
});

describe('ReasoningChainValidator — TritonVerdict defer (incomplete / still-streaming chain)', () => {
  it('defers (Abstain) on a pending step instead of accepting or rejecting', () => {
    const v = new ReasoningChainValidator();
    // The head [10, 30] is valid; the third step has not arrived yet.
    const verdict = v.validateChain([
      { closurePosition: 10 },
      { closurePosition: 30 },
      { closurePosition: 0, pending: true },
    ]);
    // Deferred chains report valid:false so accept-path callers never treat
    // an unfinished chain as validated — but the verdict is Abstain, NOT a
    // reject. That neutral middle is the value-add over the old boolean.
    expect(verdict.valid).toBe(false);
    expect(verdict.verdict).toBe(Verdict.Abstain);
    expect(isDefer(verdict.verdict)).toBe(true);
    expect(isReject(verdict.verdict)).toBe(false);
    if (!verdict.valid) {
      expect(verdict.reason).toBe('deferred');
      expect(verdict.deferred).toBe(true);
      expect(verdict.pendingAtIndex).toBe(2);
      expect(verdict.stepCount).toBe(2); // two valid steps consumed before defer
      expect(verdict.foldStepsTotal).toBe(1); // closureIndex(10)=0 + closureIndex(30)=1
    } else {
      throw new Error('expected a deferred verdict');
    }
  });

  it('streaming variant defers WITHOUT pulling the tail past a pending step', () => {
    const yielded: number[] = [];
    function* chain(): Generator<ReasoningStep> {
      yielded.push(0);
      yield { closurePosition: 10 };
      yielded.push(1);
      yield { closurePosition: 0, pending: true }; // not yet arrived
      yielded.push(2);
      yield { closurePosition: 30 };
    }
    const v = new ReasoningChainValidator();
    const verdict: ChainVerdict = v.validateChainStreaming(chain());
    expect(verdict.valid).toBe(false);
    expect(verdict.verdict).toBe(Verdict.Abstain);
    // Lazy producer stays lazy: it yielded 0 and 1 but was NOT advanced past
    // the pending step.
    expect(yielded).toContain(0);
    expect(yielded).toContain(1);
    expect(yielded).not.toContain(2);
  });
});

describe('coherenceRatio — partial validity reporting', () => {
  it('empty chain has coherence 1 (vacuously coherent)', () => {
    expect(coherenceRatio([])).toBe(1);
  });

  it('all-valid chain has coherence 1', () => {
    expect(
      coherenceRatio([
        { closurePosition: 10 },
        { closurePosition: 30 },
        { closurePosition: 90 },
      ]),
    ).toBe(1);
  });

  it('mixed-validity chain returns the correct fraction', () => {
    // 2 valid (10, 30) of 4 total = 0.5
    const r = coherenceRatio([
      { closurePosition: 10 },
      { closurePosition: 11 },
      { closurePosition: 30 },
      { closurePosition: 5 },
    ]);
    expect(r).toBe(0.5);
  });

  it('all-invalid chain has coherence 0', () => {
    expect(
      coherenceRatio([
        { closurePosition: 11 },
        { closurePosition: 5 },
        { closurePosition: 100 },
      ]),
    ).toBe(0);
  });
});

describe('ReasoningChainValidator — speed', () => {
  it('validates a 10000-step valid chain without pathological slowdown', () => {
    // Cycle through valid closure values to keep the chain long but in-tower.
    const closures = [10, 30, 90, 270, 810, 2430, 7290];
    const chain: ReasoningStep[] = [];
    for (let i = 0; i < 10000; i++) {
      chain.push({ closurePosition: closures[i % closures.length] });
    }
    const v = new ReasoningChainValidator();
    const t0 = performance.now();
    const verdict = v.validateChain(chain);
    const elapsed = performance.now() - t0;
    expect(verdict.valid).toBe(true);
    // Shared runners and local full-quality sweeps can introduce enough
    // scheduler noise to exceed the old 100ms wall-clock budget. Keep this as
    // a regression guard for pathological slowdowns, not a microbenchmark.
    expect(elapsed).toBeLessThan(250);
  });
});
